/*Table structure for table `tv_api_users` */

DROP TABLE IF EXISTS `tv_api_users`;

CREATE TABLE `tv_api_users` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `client_id` varchar(30) NOT NULL,
  `client_secret` varchar(255) NOT NULL,
  `ip_address` varchar(40) NOT NULL COMMENT 'ipv6',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `client_id` (`client_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=latin1 COMMENT='TV Users that will connect to HMSApi';

/*Data for the table `tv_api_users` */

