/*Table structure for table `tv_hms_tokens` */

DROP TABLE IF EXISTS `tv_hms_tokens`;

CREATE TABLE `tv_hms_tokens` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `ip_address` varchar(40) NOT NULL COMMENT 'ipv6',
  `token` char(89) NOT NULL,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK_USERNAME_IP` (`username`,`ip_address`),
  KEY `IDX_TOKEN` (`token`),
  KEY `IDX_USERNAME` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=latin1 COMMENT='Genesis-HMS user tokens';

/*Data for the table `tv_hms_tokens` */

