/*Table structure for table `tv_rooms` */

DROP TABLE IF EXISTS `tv_rooms`;

CREATE TABLE `tv_rooms` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `room_no` varchar(50) NOT NULL,
  `room_cat` varchar(50) NOT NULL,
  `server_id` varchar(30) NOT NULL,
  `status` tinyint(2) NOT NULL DEFAULT '0',
  `description` varchar(500) NOT NULL DEFAULT '',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `expires_at` datetime DEFAULT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=432 DEFAULT CHARSET=latin1 COMMENT='Licensed rooms for TV Servers';

