/*Table structure for table `tv_servers` */

DROP TABLE IF EXISTS `tv_servers`;

CREATE TABLE `tv_servers` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `server_id` varchar(20) NOT NULL,
  `url` varchar(200) NOT NULL COMMENT 'full url, with protocol://ip:port/path',
  `port` smallint(5) unsigned NOT NULL DEFAULT '443',
  `ip_address` varchar(40) NOT NULL COMMENT 'ipv6',
  `client_id` varchar(30) NOT NULL,
  `client_secret` varchar(150) NOT NULL,
  `access_token` varchar(150) DEFAULT NULL,
  `refresh_token` varchar(150) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `status` tinyint(3) NOT NULL DEFAULT '1',
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `server_id` (`server_id`),
  KEY `is_deleted` (`is_deleted`),
  KEY `url` (`url`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=latin1 COMMENT='TV API Servers';

/*Data for the table `tv_servers` */

