/*Table structure for table `tv_subscriptions` */

DROP TABLE IF EXISTS `tv_subscriptions`;

CREATE TABLE `tv_subscriptions` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(50) NOT NULL,
  `callback_uri` text NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Data for the table `tv_subscriptions` */

/*Table structure for table `tv_wp_group_permissions` */

DROP TABLE IF EXISTS `tv_wp_group_permissions`;

CREATE TABLE `tv_wp_group_permissions` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `group_code` char(36) NOT NULL,
  `perm_code` varchar(30) NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_group_permissions_group_perm` (`group_code`,`perm_code`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=latin1;

