/*Table structure for table `tv_wp_permissions` */

DROP TABLE IF EXISTS `tv_wp_permissions`;

CREATE TABLE `tv_wp_permissions` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `perm_code` varchar(30) NOT NULL,
  `module_code` varchar(30) NOT NULL,
  `action_name` varchar(50) NOT NULL,
  `description` varchar(500) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `perm_code` (`perm_code`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=latin1 COMMENT='Web Portal permissions list';

